// src/components/OdontogramaAvancado.js
import React, { useState } from "react";
import ModalTratamentoFace from "./ModalTratamentoFace";

// Dentes permanentes (superior e inferior, formato padrão FDI)
const dentesPermanentes = [
  [18, 17, 16, 15, 14, 13, 12, 11, 21, 22, 23, 24, 25, 26, 27, 28],
  [48, 47, 46, 45, 44, 43, 42, 41, 31, 32, 33, 34, 35, 36, 37, 38]
];

// Dentes decíduos
const dentesDeciduos = [
  ["55", "54", "53", "52", "51", "61", "62", "63", "64", "65"],
  ["85", "84", "83", "82", "81", "71", "72", "73", "74", "75"]
];

// Legenda
const statusLegenda = {
  aberto: { cor: "#fbbf24", texto: "Aberto 🦷" },
  finalizado: { cor: "#a3e635", texto: "Finalizado 🦷" },
  anotacao: { cor: "#6366f1", texto: "Anotações !" }
};
const ordemStatus = ["aberto", "finalizado", "anotacao", ""]; // "" = sem status

export default function OdontogramaAvancado() {
  const [aba, setAba] = useState("permanentes");
  const [status, setStatus] = useState({});
  const [modal, setModal] = useState({ open: false, dente: null, face: null });
  const dentes = aba === "permanentes" ? dentesPermanentes : dentesDeciduos;

  // Exibe modal ao clicar em uma face
  function handleFaceClick(num, face) {
    setModal({ open: true, dente: num, face });
  }

  // Salva tratamento (pode integrar com backend)
  function handleSaveTratamento(trat) {
    alert(`Salvo: ${trat.tratamento} em ${trat.face} do dente ${trat.dente}`);
    setModal({ open: false, dente: null, face: null });
  }

  return (
    <div className="max-w-4xl mx-auto p-6 bg-white rounded-2xl shadow-lg">
      {/* Abas */}
      <div className="flex mb-6 gap-2 justify-center">
        <button
          className={`px-4 py-1 rounded ${
            aba === "permanentes"
              ? "bg-blue-600 text-white"
              : "bg-gray-200 text-gray-700"
          }`}
          onClick={() => setAba("permanentes")}
        >
          Permanentes
        </button>
        <button
          className={`px-4 py-1 rounded ${
            aba === "deciduos"
              ? "bg-blue-600 text-white"
              : "bg-gray-200 text-gray-700"
          }`}
          onClick={() => setAba("deciduos")}
        >
          Decíduos
        </button>
      </div>

      {/* Filtros (somente visual) */}
      <div className="flex gap-2 mb-6 flex-wrap justify-center">
        <Filtro label="Maxila" />
        <Filtro label="Mandíbula" />
        <Filtro label="Face" />
        <Filtro label="Arcada superior" />
        <Filtro label="Arcada inferior" />
        <Filtro label="Arcadas" />
      </div>

      {/* Dentes */}
      <div className="mb-8 flex flex-col gap-4 items-center">
        {dentes.map((linha, idx) => (
          <div key={idx} className="flex flex-row justify-center gap-2">
            {linha.map((num) => (
              <DenteSVG
                key={num}
                numero={num}
                onFaceClick={handleFaceClick}
                status={status[num] || ""}
              />
            ))}
          </div>
        ))}
      </div>

      {/* Legenda */}
      <div className="flex gap-6 justify-center mb-2 flex-wrap">
        {Object.entries(statusLegenda).map(([key, val]) => (
          <div key={key} className="flex items-center gap-2">
            <span
              style={{
                display: "inline-block",
                width: 18,
                height: 18,
                borderRadius: "50%",
                background: val.cor,
                border: "1.5px solid #333"
              }}
            />
            <span style={{ color: val.cor }}>{val.texto}</span>
          </div>
        ))}
      </div>

      {/* Modal de tratamento de face */}
      <ModalTratamentoFace
        open={modal.open}
        face={modal.face}
        dente={modal.dente}
        onClose={() => setModal({ open: false, dente: null, face: null })}
        onSave={handleSaveTratamento}
      />
    </div>
  );
}

// Componente visual dos filtros (só visual, não filtra ainda)
function Filtro({ label }) {
  return (
    <button
      type="button"
      className="px-4 py-1 rounded-full bg-gray-100 text-gray-700 border border-gray-300 text-sm"
      tabIndex={-1}
    >
      {label}
    </button>
  );
}

// Dente SVG com faces interativas
function DenteSVG({ numero, onFaceClick }) {
  return (
    <svg width={48} height={62} viewBox="0 0 48 62" style={{ margin: 2 }}>
      {/* Coroa */}
      <polygon
        points="12,8 36,8 33,18 15,18"
        fill="#fffbe7"
        stroke="#b4b4b4"
        strokeWidth={2}
        onClick={() => onFaceClick(numero, "Coroa")}
        style={{ cursor: "pointer" }}
      />
      {/* Vestibular */}
      <polygon
        points="15,18 33,18 30,33 18,33"
        fill="#e0f2fe"
        stroke="#b4b4b4"
        strokeWidth={2}
        onClick={() => onFaceClick(numero, "Vestibular")}
        style={{ cursor: "pointer" }}
      />
      {/* Palatina/Lingual */}
      <polygon
        points="15,18 33,18 36,55 12,55"
        fill="#e7e7ff"
        stroke="#b4b4b4"
        strokeWidth={2}
        onClick={() => onFaceClick(numero, "Palatina/Lingual")}
        style={{ cursor: "pointer" }}
      />
      {/* Mesial (proximal esquerda) */}
      <polygon
        points="12,8 15,18 12,55"
        fill="#fef9c3"
        stroke="#b4b4b4"
        strokeWidth={2}
        onClick={() => onFaceClick(numero, "Mesial")}
        style={{ cursor: "pointer" }}
      />
      {/* Distal (proximal direita) */}
      <polygon
        points="36,8 33,18 36,55"
        fill="#fef3c7"
        stroke="#b4b4b4"
        strokeWidth={2}
        onClick={() => onFaceClick(numero, "Distal")}
        style={{ cursor: "pointer" }}
      />
      {/* Número do dente */}
      <text
        x={24}
        y={60}
        fontSize={14}
        fill="#1A1C2C"
        textAnchor="middle"
        fontWeight={600}
      >
        {numero}
      </text>
    </svg>
  );
}
